WITH "sample" AS (SELECT * EXCLUDE (_sf_sample_hash) FROM (SELECT t.*, ABS(HASH(*)) AS _sf_sample_hash FROM "FAKE_PROJECT"."DATASET"."ORDERS" AS t) WHERE MOD(_sf_sample_hash, 10) < 1 LIMIT 100000) SELECT "STATUS" FROM "sample" WHERE "STATUS" IS NOT NULL AND "STATUS" NOT IN ('placed', 'shipped', 'cancelled')